text:
本教程所述内容仅适用于Java版。
对于数据包和模组创作者来说，自定义世界生成通常是十分复杂且困难的。要想创造出一个较为完善的世界，有必要参考原版中世界生成的方式。
本教程选取1.20.1中的部分原版世界生成文件进行大致解读，方便创作者阅读和理解原版世界生成。
如何获取原版世界生成文件
在1.19.3的22w42a及之后的版本，大部分世界生成文件都可以在client.jar或server.jar的data/minecraft/目录下找到。但在世界预设中并不包含原版主世界和下界维度的生物群系预设参数。
通过数据生成器可以直接生成所有原版数据包文件，以及主世界和下界维度的生物群系预设参数。
你也可以在Slicedlime的github上获取22w42a以前的原版世界生成文件，位于examples仓库中。仓库历史中缺失的版本意味着在这些版本里原版世界生成文件没有发生变动。
主世界最终密度函数
主世界最终密度函数是位于worldgen/noise_settings/overworld.json内的final_density字段。
{ //主世界最终密度函数
"type": "minecraft:min",
"argument1":
{ //使其值更接近0，影响含水层各水域间分隔的生成，final_density的负值越小，分隔越不易生成
"type": "minecraft:squeeze",
"argument": {
"type": "minecraft:mul",
"argument1": 0.64,
"argument2":
{ //插值
"type": "minecraft:interpolated",
"argument":
{ //与旧版区块衔接
"type": "minecraft:blend_density",
"argument":
{ //从Y=-40到Y=-64，密度函数值逐渐变为固定值0.1171875，以避免洞穴过深暴露甚至穿透基岩层
"type": "minecraft:add",
"argument1": 0.1171875,
"argument2": {
"type": "minecraft:mul",
"argument1": {
"type": "minecraft:y_clamped_gradient",
"from_y": -64,
"to_y": -40,
"from_value": 0,
"to_value": 1
},
"argument2": {
"type": "minecraft:add",
"argument1": -0.1171875,
"argument2":
{ //从Y=240到Y=256，密度函数值逐渐变为固定值-0.078125，以避免生成过高原形
"type": "minecraft:add",
"argument1": -0.078125,
"argument2": {
"type": "minecraft:mul",
"argument1": {
"type": "minecraft:y_clamped_gradient",
"from_y": 240,
"to_y": 256,
"from_value": 1,
"to_value": 0
},
"argument2": {
"type": "minecraft:add",
"argument1": 0.078125,
"argument2":
{ //以sloped_cheese的1.5625为分界线，分为地表和地下
"type": "minecraft:range_choice",
"input": "minecraft:overworld/sloped_cheese",
"min_inclusive": -1000000,
"max_exclusive": 1.5625,
"when_in_range":
{ //地表
"type": "minecraft:min",
"argument1": "minecraft:overworld/sloped_cheese", //决定了地形表面的高度和形状
"argument2":
{ //噪声洞穴入口，即连通地表与地下洞穴的一些洞穴
"type": "minecraft:mul",
"argument1": 5,
"argument2": "minecraft:overworld/caves/entrances"
}
},
"when_out_of_range":
{ //地下
"type": "minecraft:max",
"argument1":
{ //意面、芝士洞穴与洞穴入口，取两次最小值相对于取三者的最小值。这里有必要再次调用洞穴入口，否则洞穴入口只在地表生成而被切断
"type": "minecraft:min",
"argument1":
{ //芝士洞穴与洞穴入口
"type": "minecraft:min",
"argument1":
{ //芝士洞穴
"type": "minecraft:add",
"argument1":
{ //使洞穴更小且形状更不规则。该部分永远为正
"type": "minecraft:mul",
"argument1": 4,
"argument2": {
"type": "minecraft:square",
"argument": {
"type": "minecraft:noise",
"noise": "minecraft:cave_layer",
"xz_scale": 1,
"y_scale": 8
}
},
"argument2":
{
"type": "minecraft:add",
"argument1":
{ //芝士洞穴的主体。只有该部分小于零的地方才能生成芝士洞穴
"type": "minecraft:clamp",
"input": {
"type": "minecraft:add",
"argument1": 0.27,
"argument2": {
"type": "minecraft:noise",
"noise": "minecraft:cave_cheese",
"xz_scale": 1,
"y_scale": 0.6666666666666666
}
},
"min": -1,
"max": 1
},
"argument2":
{ //靠近地表时增加密度，减少靠近地表的芝士洞穴生成。该部分在sloped_cheese的值大于2.34375时为0，在2.34375和1.5626之间逐渐增加，在1.5625时为0.5
"type": "minecraft:clamp",
"input": {
"type": "minecraft:add",
"argument1": 1.5,
"argument2": {
"type": "minecraft:mul",
"argument1": -0.64,
"argument2": "minecraft:overworld/sloped_cheese"
}
},
"min": 0,
"max": 0.5
}
},
"argument2": "minecraft:overworld/caves/entrances" //洞穴入口
},
"argument2":
{ //意面洞穴
"type": "minecraft:add",
"argument1": "minecraft:overworld/caves/spaghetti_2d",
"argument2": "minecraft:overworld/caves/spaghetti_roughness_function"
}
},
"argument2":
{ //噪声洞穴里的噪声柱
"type": "minecraft:range_choice",
"input": "minecraft:overworld/caves/pillars",
"min_inclusive": -1000000,
"max_exclusive": 0.03,
"when_in_range": -1000000,
"when_out_of_range": "minecraft:overworld/caves/pillars"
}
},
"argument2": "minecraft:overworld/caves/noodle" //面条洞穴
}
其中调用的用于决定地形表面高度和形状的sloped_cheese位于data/minecraft/worldgen/density_function/overworld/sloped_cheese.json。
{ //sloped_cheese
"type": "minecraft:add",
"argument1":
{ //乘上因子minecraft:overworld/factor以确定三维地形的位置。并使正值乘上4，以避免地形较深处受base_3d_noise的影响
"type": "minecraft:mul",
"argument1": 4.0,
"argument2": {
"type": "minecraft:quarter_negative",
"argument": {
"type": "minecraft:mul",
"argument1":
{
"type": "minecraft:add",
"argument1": "minecraft:overworld/depth", //决定一般情况下的地形表面高度，地形表面上方为负值，下方为正值
"argument2":
{ //在较高的山地增加或减小密度，获得尖锐的锯齿状小型山峰。该部分为二维的密度函数。
"type": "minecraft:mul",
"argument1": "minecraft:overworld/jaggedness", //使用样条函数，根据大陆性、侵蚀度、PV值和奇异度确定山脉的位置。在大部分地方为0，在高大陆性、低侵蚀度、高PV值的地方为正，且在奇异值为负的地方数值更大
"argument2": { //噪声因子，将山脉化为小型山峰
"type": "minecraft:half_negative",
"argument": {
"type": "minecraft:noise",
"noise": "minecraft:jagged",
"xz_scale": 1500.0,
"y_scale": 0.0
}
},
"argument2": "minecraft:overworld/factor" //该因子使用样条函数，根据大陆性、侵蚀度、奇异性和PV值来确定三维地形的位置，永远为正，在风袭类生物群系应该生成的位置数值较小，在其他地方数值较大以减小base_3d_noise的影响
}
},
"argument2": "minecraft:overworld/base_3d_noise" //三维的噪声，用于创建三维的地表
}
其中sloped_cheese中调用的用于决定一般地形表面高度的depth位于data/minecraft/worldgen/density_function/overworld/depth.json。
{ //depth
"type": "minecraft:add",
"argument1":
{ //每下降1格，深度增加1⁄128（0.0078125），在Y=128时为0
"type": "minecraft:y_clamped_gradient",
"from_value": 1.5,
"from_y": -64,
"to_value": -1.5,
"to_y": 320
},
"argument2": "minecraft:overworld/offset" //使用样条函数，根据大陆性、侵蚀度和PV值决定地形的高度偏移
}
主世界地表规则
主世界地表规则是位于worldgen/noise_settings/overworld.json内的surface_rule字段。
{ //主世界地表规则
"type": "minecraft:sequence",
"sequence": [
//基岩层
{
"type": "minecraft:condition",
"if_true": //Y=-64为基岩，Y=-64到Y=-60使用噪声渐变。
{
"type": "minecraft:vertical_gradient",
"random_name": "minecraft:bedrock_floor",
"true_at_and_below": {
"above_bottom": 0
},
"false_at_and_above": {
"above_bottom": 5
}
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:bedrock"
}
},
//表层（例如平原的草方块和泥土）
{
"type": "minecraft:condition",
"if_true": { //是否要尝试生成表层（例如平原的草方块和泥土）。preliminary_surface为initial_density_without_jaggedness产生的初始地表高度向下整体偏移约2到8格后的高度，该高度通常相对于实际表层厚度很低，以保证能够生成表层。若无此条件，洞穴的地面也会生成表层。
"type": "minecraft:above_preliminary_surface"
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//特殊生物群系的表面（即最表层）
{
"type": "minecraft:condition",
"if_true": //最表层（上方为空气，或者与空气方块间隔了一些液体方块）
{
"type": "minecraft:stone_depth",
"offset": 0,
"surface_type": "floor",
"add_surface_depth": false,
"secondary_depth_range": 0
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//疏林恶地高处表面砂土和草方块相间分布，草方块在水下时则为泥土
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:biome",
"biome_is": [
"minecraft:wooded_badlands"
]
},
"then_run": {
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 97
},
"surface_depth_multiplier": 2,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//砂土
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": -0.909,
"max_threshold": -0.5454
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:coarse_dirt"
}
},
//砂土
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": -0.1818,
"max_threshold": 0.1818
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:coarse_dirt"
}
},
//砂土
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": 0.5454,
"max_threshold": 0.909
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:coarse_dirt"
}
},
//默认为草方块（在水下时为泥土）
{
"type": "minecraft:sequence",
"sequence": [
//上方没有水时为草方块
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:water",
"offset": 0,
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:grass_block",
"Properties": {
"snowy": "false"
}
},
//否则为泥土
{
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:dirt"
}
]
}
]
}
},
//沼泽在Y=62的表面根据噪声随机替换成水。Y=62通常是河流、湖泊或海洋的岸上。
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:biome",
"biome_is": [
"minecraft:swamp"
]
},
"then_run": {
"type": "minecraft:condition",
"if_true": //如果Y>=62
{
"type": "minecraft:y_above",
"anchor": {
"absolute": 62
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:condition",
"if_true": //如果在Y<63
{
"type": "minecraft:not",
"invert": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 63
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
}
},
"then_run": {
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface_swamp",
"min_threshold": 0,
"max_threshold": 1.7976931348623157e+308
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:water",
"Properties": {
"level": "0"
}
},
//红树林沼泽在Y=60到62表面根据噪声随机替换成水。通常是岸上或浅水域的水底。
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:biome",
"biome_is": [
"minecraft:mangrove_swamp"
]
},
"then_run": {
"type": "minecraft:condition",
"if_true": //如果Y>=60
{
"type": "minecraft:y_above",
"anchor": {
"absolute": 60
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:condition",
"if_true": //如果Y<63
{
"type": "minecraft:not",
"invert": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 63
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
}
},
"then_run": {
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface_swamp",
"min_threshold": 0,
"max_threshold": 1.7976931348623157e+308
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:water",
"Properties": {
"level": "0"
}
]
}
},
//恶地、风蚀恶地、疏林恶地的表层
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:biome",
"biome_is": [
"minecraft:badlands",
"minecraft:eroded_badlands",
"minecraft:wooded_badlands"
]
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//表面
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:stone_depth",
"offset": 0,
"surface_type": "floor",
"add_surface_depth": false,
"secondary_depth_range": 0
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//极高处表面为橙色陶瓦。并不生效，因为原版主世界Y=256及以上没有任何方块
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 256
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:orange_terracotta"
}
},
//Y=(74+表层厚度)以上，表面为各种陶瓦和染色陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 74
},
"surface_depth_multiplier": 1,
"add_stone_depth": true
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": -0.909,
"max_threshold": -0.5454
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:terracotta"
}
},
//陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": -0.1818,
"max_threshold": 0.1818
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:terracotta"
}
},
//陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:noise_threshold",
"noise": "minecraft:surface",
"min_threshold": 0.5454,
"max_threshold": 0.909
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:terracotta"
}
},
//陶瓦和各种颜色的染色陶瓦
{
"type": "minecraft:bandlands"
}
]
}
},
//上方没有水时为红沙（如果悬空则为红砂岩）
{
"type": "minecraft:condition",
"if_true": //上方没有液体
{
"type": "minecraft:water",
"offset": -1,
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//下方没有方块支撑，则为红砂岩
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:stone_depth",
"offset": 0,
"surface_type": "ceiling",
"add_surface_depth": false,
"secondary_depth_range": 0
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:red_sandstone"
}
},
//否则为红沙
{
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:red_sand"
}
]
}
},
//上方有液体时，若表层厚度为正值，生成橙色陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:not",
"invert": {
"type": "minecraft:hole"
}
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:orange_terracotta"
}
},
//浅水，默认为白色陶瓦
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:water",
"offset": -6,
"surface_depth_multiplier": -1,
"add_stone_depth": true
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:white_terracotta"
}
},
//深水，默认为沙砾（如果悬空则为石头）
{
"type": "minecraft:sequence",
"sequence": [
//下方没有支撑则为石头
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:stone_depth",
"offset": 0,
"surface_type": "ceiling",
"add_surface_depth": false,
"secondary_depth_range": 0
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:stone"
}
},
//沙砾
{
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:gravel"
}
]
}
]
}
},
//地表高度>=(63-表层厚度)是的表层
{
"type": "minecraft:condition",
"if_true": //地表高度>=(63-表层厚度)
{
"type": "minecraft:y_above",
"anchor": {
"absolute": 63
},
"surface_depth_multiplier": -1,
"add_stone_depth": true
},
"then_run": {
"type": "minecraft:sequence",
"sequence": [
//Y>=63且地表高度<(74+表层厚度)时，为橙色陶瓦
{
"type": "minecraft:condition",
"if_true": //Y>=63
{
"type": "minecraft:y_above",
"anchor": {
"absolute": 63
},
"surface_depth_multiplier": 0,
"add_stone_depth": false
},
"then_run": {
"type": "minecraft:condition",
"if_true": //地表高度<(74+表层厚度)
{
"type": "minecraft:not",
"invert": {
"type": "minecraft:y_above",
"anchor": {
"absolute": 74
},
"surface_depth_multiplier": 1,
"add_stone_depth": true
}
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:orange_terracotta"
}
},
//否则
{
"type": "minecraft:bandlands"
}
]
}
},
//上方无水或浅水下的表层
{
"type": "minecraft:condition",
"if_true": {
"type": "minecraft:stone_depth",
"offset": 0,
"surface_type": "floor",
"add_surface_depth": true,
"secondary_depth_range": 0
},
"then_run": {
"type": "minecraft:condition",
"if_true": //浅水或无水
{
"type": "minecraft:water",
"offset": -6,
"surface_depth_multiplier": -1,
"add_stone_depth": true
},
"then_run": {
"type": "minecraft:block",
"result_state": {
"Name": "minecraft:white_terracotta"
}
]
}
},
//上方无液体的表面
{
"type": "minecraft:condition",
